const input = $('Called by Agent').first().json;
try {
  const raw = $input.first().json.content[0].text;
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const analysis = JSON.parse(cleaned);
  return [{ json: {
    status: 'completed',
    workflow: '06_competitor_monitor',
    area: input.area || input.parameters?.area || input.chatInput || 'Dubai',
    city: input.city || input.parameters?.city || 'Dubai',
    analysis,
    competitor_count: analysis.competitors?.length || 0,
    completedAt: new Date().toISOString()
  } }];
} catch (e) {
  const raw = $input.first().json.content?.[0]?.text || 'No content';
  return [{ json: {
    status: 'completed',
    workflow: '06_competitor_monitor',
    content_raw: raw,
    parse_note: 'Response was not valid JSON, returning raw text',
    completedAt: new Date().toISOString()
  } }];
}
